---@class LWonderRoleObject
local LWonderRoleObject = LxClass("LWonderRoleObject", nil)
--local LUIJumpTimeActor = LxRequire("LApp.UI.Display.LUIJumpTimeActor")
local LBubbleStick = LxRequire("LApp.gameplay.Common.LBubbleStick")
local typeofBtObjectView = typeof(CardEHT.BtObjectView)
LXImport("..Ctrl.LWonderHudCtrl")
function LWonderRoleObject:LWonderRoleObject(mgr)
    ---@type LWonderManager|LDreamTripManager
    self._mgr = mgr
end

function LWonderRoleObject:Create(objData,extraData)
    self._objData = objData

    self._extraData = extraData

    self._effList = {}

    self._effCacheList ={}

    ---@type LDisplaySpine
    self._obj=nil


    ---@type SequenceCom
    self._seqCom = SequenceCom:New()

    self._hudCtrl = LWonderHudCtrl:New()

    self._loopTimer = LxTimer.LoopTimeCall(function()
        self:OnRun()
    end,0,false,-1)
end

function LWonderRoleObject:StartLoad()
    if self._obj then
        return
    end

    self._leadingType = self._objData.leadingType

    local key = self._objData.key
    local func = self._objData.func
    local sortingNum = self._objData.sortingNum or LGamePlayType.WONDER_SORTING_ROLE
    local spineName = self._objData.spineName
    local pos = self._objData.pos
    local scale = self._objData.scale
    local nextPos = self._objData.nextPos
    local isLeft
    if nextPos then
        local topX = nextPos.x - pos.x
        if topX ~= 0 then
            isLeft = topX < 0
        end
    end
    local spineData =
    {
        key = key,
        resName = spineName,
        pos = pos,
        nextPos = nextPos,
        isLeft = isLeft,
        scale = scale,
        sorting = sortingNum,
        endFunc = function(spine)
            self._obj = spine
            self:InitBtObjectView(spine)
            for k,v in ipairs(self._effCacheList) do
                self:CreateEff(v)
            end

            if func then
                func(spine)
            end
        end
    }

    self._mgr:GetObjCtrl():MakeObject(spineData)
end

function LWonderRoleObject:InitBtObjectView(spine)
    local dpTrans = spine:GetSpineTrans()
    local dpGo = dpTrans.gameObject

    local comp = dpGo:GetComponent(typeofBtObjectView)
    if(not comp) then
        comp = dpGo:AddComponent(typeofBtObjectView)
    end
    self._btObjectView = comp
end

function LWonderRoleObject:GetBtObjectView()
    return self._btObjectView
end

function LWonderRoleObject:AddEffect(effData)
    if not self._obj or not self._obj:IsDpValid() then
        table.insert(self._effCacheList,effData)
        return
    end

    self:CreateEff(effData)
end

function LWonderRoleObject:CreateEff(effData)
    local effName = effData.effName
    local effType = effData.type
    local duration = effData.duration or -1
    local eff = self._effList[effName]
    if eff then
        if effType == 1 then
            local tEffData = self._mgr:GetEffCtrl():GetEffByKey(eff.key)
            if tEffData then
                self:ReplayEffOne(eff)
                self:DelayDelete(effName,duration)
            end
            return
        end
    end


    if effType == 1 then
        self:CreateEffTypeOne(effData)
    elseif effType == 2 then
        self:CreateEffTypeTwo(effData)
    end


end

function LWonderRoleObject:ReplayEffOne(eff)

    local effectData = self._mgr:GetEffCtrl():GetEffByKey(eff.key)
    local effect = effectData.effect
    local dpTrans = effect:GetDisplayTrans()
    if CS.IsValidObject(dpTrans)  then
        -- false 到 true 重新播特效
        dpTrans.gameObject:SetActive(false)
        dpTrans.gameObject:SetActive(true)
    end
end


function LWonderRoleObject:CreateEffTypeOne(effData)
    local effName = effData.effName
    local duration = effData.duration or -1

    local offset = effData.offset or Vector3.zero
    local trans = self._obj:GetSpineTrans()
    local effData =
    {
        trans = trans,
        type = "effect",
        key = effName,
        resName = effName,
        pos = offset,
        scale = effData.scale
    }

    self._mgr:GetEffCtrl():MakeObject(effData)
    self._effList[effName] = effData
    self:DelayDelete(effName,duration)

end

function LWonderRoleObject:CreateEffTypeTwo(effData)
    local effName = effData.effName
    local duration = effData.duration or -1

    local offset = effData.offset or Vector3.zero
    local trans = self._obj:GetSpineTrans()
    local effData =
    {
        root = trans,
        type = "spine",
        key = effName,
        resName = effName,
        localPos = offset,
        scale = effData.scale,
        sorting = 3
    }

    self._mgr:GetObjCtrl():MakeObject(effData)
    self._effList[effName] = effData
    self:DelayDelete(effName,duration)

end


function LWonderRoleObject:DelayDelete(effName,duration)
    if duration>0 then
        local seq = self._seqCom:CreateSeq(effName)
        seq:AppendInterval(duration)
        seq:OnComplete(function ()
            self._seqCom:DeleteSeq(effName)
            self:DeleteEffect(effName)
        end)
        seq:PlayForward()
    end
end

function LWonderRoleObject:DeleteEffect(effName)
    local eff = self._effList[effName]
    self._effList[effName] = nil
    if eff then
        if eff.type == "effect" then
            self._mgr:GetEffCtrl():DestroyByKey(eff.key)
        elseif eff.type == "spine" then
            self._mgr:GetObjCtrl():DestroyByKey(eff.key)
        end
    end

    local cnt = #self._effCacheList
    for i = cnt,1,-1 do
        if self._effCacheList[i].effName == effName then
            table.remove(self._effCacheList,i)
        end
    end
end

function LWonderRoleObject:PlayBeHit(duration)
