    if not spine or not spine:IsDpValid() then
        return
    end

    self._aniEndTime = self:GetTime() + duration

    local animation = "hit1"
    spine:PlayAnimation(0,animation,false)

    --self:CreateHud()
end

function LWonderRoleObject:PlayIdle()
    local spine = self._obj
    if not spine or not spine:IsDpValid() then
        return
    end
    spine:PlayAnimation(0,"idle",true)
end

function LWonderRoleObject:JumpTo(jumpData)
    local spine = self._obj
    if not spine or not spine:IsDpValid() then
        return
    end

    local toPos = jumpData.targetPos
    local endCall = jumpData.endCall

    local pos = self._obj:GetDisplayTrans().position

    local bDown = pos.y >= toPos.y

    local aniName = "jump1"
    if bDown then
        aniName = "jump2"
    end
    spine:PlayAnimation(0,aniName,true)
    local btObjectView = self:GetBtObjectView()
    local speed = 2

    local disY = Mathf.Abs(pos.y - toPos.y)
    local disX = Mathf.Abs(pos.x - toPos.x)
    local dis = Mathf.Max(disX,disY)

    local time = dis / speed
    if time > 0.8 then time = 0.8 end
    if time < 0.1 then time = 0.1 end
    local topY = toPos.y + 0.1
    if bDown then
        if pos.y - toPos.y > 0.15 then
            topY = pos.y + 0.5
        end
    end
    local topPos = Vector3((pos.x + toPos.x) / 2 ,topY,0)
    btObjectView:StartJump(toPos, topPos, time, 0)
    local seq = self._seqCom:CreateSeq("jumpEnd")
    self._isJumping = true
    seq:AppendInterval(time)
    seq:OnComplete(function ()
        self._seqCom:DeleteSeq("jumpEnd")
        if endCall then
            endCall()
        end
        self._isJumping = false
        self:PlayIdle()
    end)
    seq:PlayForward()
end

function LWonderRoleObject:ContinuousJumpTo(jumpPosList,endCall,CameraMoveToFunc,CameraMoveBackFunc)
    local spine = self._obj
    if not spine or not spine:IsDpValid() then
        return
    end
    local len = #jumpPosList
    if len <= 0 then return end
    self._isJumping = true
    local seq = self._seqCom:CreateSeq("jumpEnd")
    local btObjectView = self:GetBtObjectView()
    local speed = 2
    if CameraMoveToFunc then
        seq:AppendInterval(0.2)
        seq:AppendCallback(function()
            CameraMoveToFunc()
        end)
    end
    for i,v in ipairs(jumpPosList) do
        seq:AppendInterval(0.1)
        local toPos = v
        local interval = self:GetInterval(toPos,speed)
        self:SeqJump(toPos,seq,spine,btObjectView,interval)
    end
    if CameraMoveBackFunc then
        seq:AppendInterval(0.2)
        seq:AppendCallback(function()
            CameraMoveBackFunc()
        end)
    end
    seq:OnComplete(function ()
        self._seqCom:DeleteSeq("jumpEnd")
        self._isJumping = false
        if endCall then
            endCall()
        end
        self:PlayIdle()
    end)
    seq:PlayForward()
end

function LWonderRoleObject:GetInterval(toPos,speed)
    local pos = self._obj:GetDisplayTrans().position
    local disY = Mathf.Abs(pos.y - toPos.y)
    local disX = Mathf.Abs(pos.x - toPos.x)
    local dis = Mathf.Max(disX,disY)
    local interval = dis / speed
    if interval > 0.8 then interval = 0.8 end
    if interval < 0.1 then interval = 0.1 end
    return interval
end

function LWonderRoleObject:SeqJump(toPos,seq,spine,btObjectView,interval)
    seq:AppendCallback(function()
        local pos = self._obj:GetDisplayTrans().position
        local bDown = pos.y >= toPos.y
        local aniName = "jump1"
        if bDown then aniName = "jump2" end

        local topY = toPos.y + 0.1
        if bDown then
            if pos.y - toPos.y > 0.15 then
                topY = pos.y + 0.5
            end
        end
        local topX = toPos.x - pos.x
        printInfoNR(" === topX = "..topX  )
        if topX ~= 0 then
            local isLeft = topX < 0
            self._obj:SetFlipX(isLeft)
        end
        spine:PlayAnimation(0,aniName,true)
        local topPos = Vector3((pos.x + toPos.x) / 2 ,topY,0)
        btObjectView:StartJump(toPos, topPos, interval, 0)
    end)
    seq:AppendInterval(interval)
    seq:AppendCallback(function ()
        self:PlayIdle()
    end)
end

function LWonderRoleObject:StarSendRoleObj(changMapCall,endCall,targetPos)
    local spine = self._obj
    if not spine or not spine:IsDpValid() then
        return
    end
    self._isJumping = true
    local seq = self._seqCom:CreateSeq("starSendRole")
    local chuansong_1 =
    {
        type = 1,
        effName = "fx_sghl_chuansong_1",
        scale = 0.5,
        offset = Vector3.New(0,0,0),
        duration = 1,
    }
    self:AddEffect(chuansong_1)
    local changeAlpha = YXTween.TweenFloat(1, 0, 1, function(ival)
        self:SetAlpha(ival)
    end):SetEase(DG.Tweening.Ease.OutCubic)
    seq:Append(changeAlpha)
    seq:AppendInterval(0.5)
    seq:AppendCallback(function()
        if changMapCall then changMapCall() end
        local buff =
        {
            type = 1,
            effName = "fx_sghl_chuansong_2",
            scale = 0.5,
            offset = Vector3.New(0,0,0),
            duration = 1,
        }
        self:AddEffect(buff)
        self:ChangePos(targetPos)
    end)
    local showAlpha = YXTween.TweenFloat(0, 1, 1, function(ival)
        self:SetAlpha(ival)
    end):SetEase(DG.Tweening.Ease.OutCubic)
    seq:Append(showAlpha)

    seq:OnComplete(function ()
        self._seqCom:DeleteSeq("starSendRole")
        self._isJumping = false
        if endCall then endCall() end
    end)

    seq:PlayForward()
end

