function LWonderRoleObject:IsJumping()
    return self._isJumping
end

function LWonderRoleObject:SetJumping(_isJumping)
    self._isJumping = _isJumping
end

function LWonderRoleObject:Destroy()

    if self._seqCom then
        self._seqCom:Destroy()
        self._seqCom = nil
    end

    if self._loopTimer then
        LxTimer.LoopTimeStop(self._loopTimer)
        self._loopTimer  = nil
    end

    if self._obj then
        self._obj:Destroy()
        self._obj = nil
    end

    if self._effList then
        for k,v in pairs(self._effList) do
            if v.type == "effect" then
                self._mgr:GetEffCtrl():DestroyByKey(v.key)
            elseif v.type == "spine" then
                self._mgr:GetObjCtrl():DestroyByKey(v.key)
            end
        end
        self._effList = nil
    end

    if self._bubbleStick then
        self._bubbleStick:DestroyBubble()
        self._bubbleStick = nil
    end

    if self._hudCtrl then
        self._hudCtrl:Destroy()
        self._hudCtrl = nil
    end

end

