function LWonderRoleObject:AniRun(time)
    if self._aniEndTime and self._aniEndTime<time then
        self:PlayIdle()
        self._aniEndTime = nil
        if self._moveEndCall then
            self._moveEndCall()
            self._moveEndCall = nil
        end
    end
end

