function LWonderRoleObject:MoveTo(pos,endCall)
    if not self._obj then
        return
    end
    if not self._obj:IsDpValid() then
        return
    end

    local curPos = self._obj:GetDisplayTrans().position
    local targetPos = pos
    local dis = Mathf.Abs(curPos.y - targetPos.y)
    if dis<0.01 then
        return
    end
    local speed = 2
    local time = dis/speed
    time = Mathf.Clamp(time,0.1,0.8)
    self._obj:PlayAnimation(0,"run",true)
    self._aniEndTime = self:GetTime() + time
    self._btObjectView:StartMove(targetPos,time)
    self._moveEndCall = endCall
end

function LWonderRoleObject:CreateBubble(bubbleInfo)
    if self._bubbleStick then
        self._bubbleStick:DestroyBubble()
        self._bubbleStick = nil
    end
    local bubbleStick = LBubbleStick:New()
    local spine = self._obj
    if not spine or not spine:IsDpValid() then
        return
    end
    local dpTarns = spine:GetDisplayTrans()
    bubbleStick:CreateBubble("Bubble")
    bubbleStick:SetHeroTrans(dpTarns,Vector3(0,1,0))
    bubbleStick:SetContent(bubbleInfo.content,bubbleInfo.time)
    bubbleStick:SetVisible(true)
    self._bubbleStick = bubbleStick
end

function LWonderRoleObject:RunToPos(posList,CameraMoveToFunc,CameraMoveBackFunc,endCall,bubbleInfo)
    local spine = self._obj
    if not spine or not spine:IsDpValid() then
        return
    end
    self._isJumping = true
    local allTime = bubbleInfo and bubbleInfo.time or 0
    local playTime = 0
    local seq = self._seqCom:CreateSeq("runEnd")
    local btObjectView = self:GetBtObjectView()
    if CameraMoveToFunc then
        local moveToTime = 0.2
        playTime = playTime + moveToTime
        seq:AppendInterval(moveToTime)
        seq:AppendCallback(function()
            CameraMoveToFunc()
            if bubbleInfo then
                printInfoNR("==== 触发盗宝者事件")
                self:CreateBubble(bubbleInfo)
            end
        end)
    end
    local time = 0.5
    local isRun = false
    local firstRoleIndex = posList[1] and posList[1].roleIndex
    for i,v in ipairs(posList) do
        local targetPos = v.pos
        local isRole = v.isRole
        local roleIndex = v.roleIndex
        if i ~= 1 then
            playTime = playTime + time
            seq:AppendInterval(time)
        end
        if not isRun then
            seq:AppendCallback(function()
                spine:PlayAnimation(0,"run",true)
            end)
            isRun = true
        end
        seq:AppendCallback(function()
            if isRole then
                self._mgr:RefreshGridHideStatus(roleIndex,firstRoleIndex)
            end
            local pos = spine:GetDisplayTrans().position
            local topX = targetPos.x - pos.x
            if topX ~= 0 then
                local isLeft = topX < 0
                spine:SetFlipX(isLeft)
            end
            btObjectView:StartMove(targetPos,time)
        end)
    end
    local playIdle = false

    if CameraMoveBackFunc then
        local moveBackTime = 0.2
        if allTime ~= 0 and playTime < allTime then
            local tMoveBackTime = moveBackTime
            moveBackTime = allTime - playTime - tMoveBackTime
            seq:AppendInterval(tMoveBackTime)
            seq:AppendCallback(function()
                self:PlayIdle()
            end)
            playIdle = true
        end
        seq:AppendInterval(moveBackTime)
        seq:AppendCallback(function()
            CameraMoveBackFunc()
        end)
    else
        seq:AppendInterval(0.6)
    end
    if not playIdle then
        seq:AppendCallback(function()
            self:PlayIdle()
        end)
    end
    seq:OnComplete(function ()
        self._seqCom:DeleteSeq("runEnd")
        self._isJumping = false
        if endCall then
            endCall()
        end
    end)
    seq:PlayForward()
end

function LWonderRoleObject:ChangePos(toPos,endCall)
    local pos = self._obj:GetDisplayTrans().position
    local bDown = pos.y >= toPos.y
    local topY = toPos.y + 0.1
    if bDown then
        if pos.y - toPos.y > 0.15 then
            topY = pos.y + 0.5
        end
    end
    --[[    local topX = toPos.x - pos.x
        if topX ~= 0 then
            local isLeft = topX < 0
            self._obj:SetFlipX(isLeft)
        end]]
    local topPos = Vector3((pos.x + toPos.x) / 2 ,topY,0)
    local btObjectView = self:GetBtObjectView()
    btObjectView:StartJump(toPos, topPos, 0, 0)
    self:PlayIdle()
end

function LWonderRoleObject:CommonChangeDirection(targetPos,pos)
    local spine = self._obj
    if not spine or not spine:IsDpValid() then return end
    if not targetPos then return end
    pos = pos or spine:GetDisplayTrans().position
    local topX = targetPos.x - pos.x
    local topY = targetPos.y - pos.y
    local rotation
    local isLeft,isDown
    local spineName
    if topY ~= 0 then
        spine:ClearAnimation(0)
        spine:SetToSetupPose()
        isDown = topY < 0
        spineName = isDown and "idle1" or "idle2"
        printInfoNR("==== spineName = " .. spineName)
        spine:PlayAnimation(0,spineName,true,false,0)
    end
    if topX ~= 0 then
        isLeft = topX < 0
        if isLeft then
            printInfoNR("==== 想左 = ")
        else
            printInfoNR("==== 想右 = ")
        end
        spine:SetFlipX(not isLeft)
    end
    if isLeft then
        if isDown then
            rotation = Quaternion.Euler(0,0,-135)
        else
            rotation = Quaternion.Euler(0,0,135)
        end
    else
        if isDown then
            rotation = Quaternion.Euler(0,0,-45)
        else
            rotation = Quaternion.Euler(0,0,45)
        end
    end
    return rotation
end

function LWonderRoleObject:PersonChangeDirection(targetPos,pos)
    local spine = self._obj
    if not spine or not spine:IsDpValid() then return end
    if not targetPos then return end
    local isNotPos = pos == nil
    pos = pos or spine:GetDisplayTrans().position
