    local topY = targetPos.y - pos.y
    local rotation
    local isLeft,isDown
    local spineName
    if topY ~= 0 then
        spine:ClearAnimation(0)
        spine:SetToSetupPose()
        isDown = topY < 0
        spineName = isNotPos and "idle" or "run"
        printInfoNR("==== spineName = " .. spineName)
        spine:PlayAnimation(0,spineName,true,false,0)
    end
    if topX ~= 0 then
        isLeft = topX < 0
        if isLeft then
            printInfoNR("==== 想左 = ")
        else
            printInfoNR("==== 想右 = ")
        end
        spine:SetFlipX(isLeft)
    end
    --[[    if isLeft then
            if isDown then
                rotation = Quaternion.Euler(0,0,-135)
            else
                rotation = Quaternion.Euler(0,0,135)
            end
        else
            if isDown then
                rotation = Quaternion.Euler(0,0,-45)
            else
                rotation = Quaternion.Euler(0,0,45)
            end
        end]]
    rotation = Quaternion.Euler(0,0,0)
    return rotation
end

function LWonderRoleObject:GetShowLeadingType()
    return gModelCommonDreamTrip:GetShowLeadingType(self._leadingType)
end

function LWonderRoleObject:ChangeDirection(targetPos,pos)
    local rotation
    if self._leadingType then
        local showType = self:GetShowLeadingType()
        if showType == ModelDreamTrip.SHOW_LEADINGTYPE_SHIP then
            rotation = self:CommonChangeDirection(targetPos,pos)
        elseif showType == ModelDreamTrip.SHOW_LEADINGTYPE_PERSON then
            rotation = self:PersonChangeDirection(targetPos,pos)
        end
    else
        rotation = self:CommonChangeDirection(targetPos,pos)
    end
    return rotation
end

-- 梦境之旅船的移动
function LWonderRoleObject:RunToPosAndShowEff(posList,CameraMoveToFunc,CameraMoveBackFunc,endCall,bubbleInfo,changeDBZFunc,runTime)
    local spine = self._obj
    if not spine or not spine:IsDpValid() then return end
    self._isJumping = true
    local allTime = bubbleInfo and bubbleInfo.time or 0
    local playTime = 0
    local seq = self._seqCom:CreateSeq("runEnd")
    local btObjectView = self:GetBtObjectView()
    if CameraMoveToFunc then
        local moveToTime = 0.2
        playTime = playTime + moveToTime
        seq:AppendInterval(moveToTime)
        seq:AppendCallback(function()
            CameraMoveToFunc()
            if bubbleInfo then
                printInfoNR("==== 触发盗宝者喊话事件")
                self:CreateBubble(bubbleInfo)
            end
        end)
    end
    local effName
    local extraData = self._extraData
    if extraData then
        effName = gModelCommonDreamTrip:GetMapInfoByKey({
            mapType = extraData.mapType,
            sid = extraData.sid,
            key = "yidongGrid",
        })
    else
        effName = gModelDreamTrip:GetMapInfoByKey("yidongGrid")
    end
    local time = runTime or 0.2
    local effSp
    local firstRoleIndex = posList[1] and posList[1].roleIndex
    local len = #posList
    for i,v in ipairs(posList) do
        local targetPos = v.pos
        local isRole = v.isRole
        local roleIndex = v.roleIndex
        if i ~= 1 then
            playTime = playTime + time
        end
        seq:AppendCallback(function()
            if not effSp then
                local yidongEff =
                {
                    type = 1,
                    effName = effName,
                    scale = 0.5,
                    offset = Vector3.New(0,0,0),
                    duration = 1,
                }
                self:AddEffect(yidongEff)
            end
            if isRole then
                self._mgr:RefreshGridHideStatus(roleIndex,firstRoleIndex)
            end
            self._mgr:PlayRunPosEff(v.roleKey)

            local pos = spine:GetDisplayTrans().position
            local rotation = self:ChangeDirection(targetPos,pos)
            local effData = self._mgr:GetEffCtrl():GetEffByKey(effName)
            if effData and rotation then
                local effect = effData.effect
                if effect then
                    effect:SetEffectRotation(rotation)
                end
            end
            btObjectView:StartMove(targetPos,time)
        end)
        seq:AppendInterval(time)
        if i == len and changeDBZFunc then
            playTime = playTime + time
            seq:AppendInterval(time)
        end
    end
    local playIdle = false

    if CameraMoveBackFunc then
        local moveBackTime = 0.2
        if allTime ~= 0 and playTime < allTime then
            local tMoveBackTime = moveBackTime
            moveBackTime = allTime - playTime - tMoveBackTime
            seq:AppendInterval(tMoveBackTime)
            seq:AppendCallback(function()
                self:PlayIdle()
            end)
            playIdle = true
        end
        moveBackTime = moveBackTime + 0.2
        seq:AppendInterval(moveBackTime)
        seq:AppendCallback(function()
            CameraMoveBackFunc()
        end)
    else
        if self._leadingType and self:GetShowLeadingType() == ModelDreamTrip.SHOW_LEADINGTYPE_PERSON then
            seq:AppendCallback(function()
                self:PlayIdle()
            end)
        end
        seq:AppendInterval(0.6)
    end
    if not playIdle then
        seq:AppendCallback(function()
            self:PlayIdle()
        end)
    end
    seq:OnComplete(function ()
        self._seqCom:DeleteSeq("runEnd")
        self._isJumping = false
        if endCall then
            endCall()
        end
        if changeDBZFunc then
            changeDBZFunc()
        end
    end)
    seq:PlayForward()
end


function LWonderRoleObject:PlayAttack(func)
    if func then func() end
    --[[    local callBackFunc = function()
            self:PlayIdle()
            if func then func() end
        end
        local spine = self._obj
        if not spine or not spine:IsDpValid() then
            callBackFunc()
            return
        end
        spine:PlayAnimation(0,"attack1",false)
        spine:SetAnimationCompleteFunc(callBackFunc)]]
end

return LWonderRoleObject
